const { calls, context } = $json;
if (!Array.isArray(calls)) {
  return { error: 'calls must be an array of { tool, args }' };
}
const results = [];
for (const call of calls) {
  try {
    let result;
    switch (call.tool) {
      case 'read_file':
        result = require('fs').readFileSync(call.args.path, 'utf8');
        break;
      case 'list_dir':
        result = require('fs').readdirSync(call.args.path);
        break;
      case 'stat':
        result = require('fs').statSync(call.args.path);
        break;
      default:
        result = { error: `Unknown tool: ${call.tool}` };
    }
    results.push({ tool: call.tool, status: 'ok', result });
  } catch (e) {
    results.push({ tool: call.tool, status: 'error', error: e.message });
  }
}
return { batch_results: results, total: results.length, errors: results.filter(r => r.status === 'error').length };
